"""ugk/adr.py — Architectural Decision Registry + Compound Capabilities (Grundnorm 444).

ATLAS-S-03: every major architectural decision has a bound ArchitecturalDecision
record; each ADR references at least one invariant.

ATLAS-S-02: compound_capabilities maps capability names to frozensets of
invariant IDs that together produce them.
"""
from __future__ import annotations
from dataclasses import dataclass


# ---------------------------------------------------------------------------
# ArchitecturalDecision (ADR-equivalent)
# ---------------------------------------------------------------------------

@dataclass(frozen=True)
class ArchitecturalDecision:
    """Governed ADR: why this design, what was rejected, what invariants encode it.

    M2.3a addition (REV3 §Deliverable 3):
      threat_class:  Optional THR threat-class identifier. REQUIRED for ADRs
                     proposing changes to the canonical leaf set, expansions
                     to c_i input domains, or modifications to
                     PRINCIPLED_REDUNDANCY_REGISTRY. Format: short slug
                     identifier (e.g. 'chain-link-cache-self-describing-
                     identity'). None for non-binding-surface ADRs.
    """
    id:                str
    context:           str   # what problem was being solved
    decision:          str   # what was chosen
    alternatives:      tuple # what was evaluated and rejected
    consequences:      str   # what this decision implies structurally
    bound_invariants:  tuple # invariant IDs that encode this decision
    threat_class:      str = ""   # M2.3a — empty string when not binding-surface


_ADR_REGISTRY: dict[str, ArchitecturalDecision] = {}


def _adr(id, context, decision, alternatives, consequences, bound_invariants,
         threat_class=""):
    rec = ArchitecturalDecision(
        id=id, context=context, decision=decision,
        alternatives=tuple(alternatives), consequences=consequences,
        bound_invariants=tuple(bound_invariants),
        threat_class=threat_class,
    )
    _ADR_REGISTRY[id] = rec
    return rec


ADR_REGISTRY: dict[str, ArchitecturalDecision] = _ADR_REGISTRY


