AD_01 = _adr(
    id="AD-01",
    context=(
        "A flat dispatch surface allows any op to be called at any time regardless "
        "of governance status. Tier 0 kernel internals could be invoked by deployers. "
        "No status enforcement at the dispatch level."
    ),
    decision=(
        "Three-tier op jurisdiction: _KERNEL_OPS (Tier 0, internal-only), "
        "_UNIVERSAL_OPS (Tier 1, ACTIVE only, system-authority), "
        "APPLICATION_OPS (Tier 2, deployer-declared, ACTIVE only). "
        "Enforced at execute() before any gate evaluation."
    ),
    alternatives=(
        "Single dispatch table with runtime status checks",
        "Two-tier (kernel vs application) without universal ops",
        "Class hierarchy (NavigatorKernel subclasses per tier)",
        "No enforcement — convention only",
    ),
    consequences=(
        "KernelInternalOp raised for Tier 0 callers. GovernanceNotFounded in "
        "UNINITIALIZED for Tier 2. BS-01 (UL-S-03) for undeclared ops. "
        "Deployers can only extend via APPLICATION_OPS in ops.py (644)."
    ),
    bound_invariants=("CM-OP-01", "EH-S-01", "GK-S-01", "UL-S-03"),
)

AD_02 = _adr(
    id="AD-02",
    context=(
        "Advisory receipt systems write after the effect. If the effect succeeds "
        "but receipt writing fails, the operation is unrecorded. The receipt is "
        "an afterthought rather than a constitutional precondition."
    ),
    decision=(
        "Receipt-before-effect (NBER-1): write the success receipt BEFORE calling "
        "effect(). Write a failed receipt if effect() raises. The receipt is "
        "causally prior to the effect in the chain — always."
    ),
    alternatives=(
        "Advisory receipts (encouraged, not required)",
        "Post-effect receipts (receipt written after effect completes)",
        "Receipts only on session boundaries",
        "No receipts for non-governance operations",
    ),
    consequences=(
        "An effect can never execute without a prior receipt in the chain. "
        "The receipt chain is a causal record of intent, not a log of outcomes. "
        "Failure receipts exist even when effects fail."
    ),
    bound_invariants=("UL-S-02",),
)

